var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"김초원, 도착했습니다.","JPN":"スズキ・ナオ、到着しました。","ENG":"Kim Chowon here.","TWN":"金初源抵達。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그럼 지금 바로 사장님께서 도장만 찍어 주시면 끝이네요.","JPN":"では、ここで社長がハンコを押してくだされば完成ですね。","ENG":"Okay, all we need is your signature right here.","TWN":"那現在就只差老闆用印囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"부르신 이유는 사전에 파악하고 있었습니다.","JPN":"お呼びになった理由は事前に把握していました。","ENG":"I've already figured out in advance why you wanted to see me.","TWN":"我已經事前掌握好老闆找我來的原因。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그리고 제 주관에 따르면, 저와 사장님의 관계는 상당히 우수해요.","JPN":"それから、私の主観によりますと、社長との関係は極めて良好です。","ENG":"And in my opinion, our relationship is quite excellent, Boss.","TWN":"而且，就我個人淺見，我認為我和老闆非常合拍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"프로로서 제가 드린 보안 대책을 신뢰하고 반영해 주셨으니까요.","JPN":"プロとして私がご提案した保安対策を信頼し、反映してくださったのですから。","ENG":"Because you trusted me enough to implement the countermeasures I suggested as a professional.","TWN":"因為你信賴我以專家的身分給予的安全對策，而且也會落實。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"계약서를 혼인 신고서로 바꿔치기하셨다고 해도 날인을 고려할 수 있을 정도로 말이죠.","JPN":"契約書を婚姻届にすりかえられたとしても、捺印を考慮できるくらいです。","ENG":"Enough so that I would consider signing the paper even if you switched it out for a marriage certificate.","TWN":"合拍到就算你要把合約換成結婚證書，我也會考慮蓋章。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이 자리에 대한 감상 말인가요?","JPN":"この場の感想ですか？","ENG":"What are my thoughts about this place?","TWN":"對於這個位置的感想嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"……그렇네요.","JPN":"……そうですね。","ENG":"...Well.","TWN":"……這個嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사장님은 거미에 대해 얼마나 알고 계시나요?","JPN":"社長はクモについてどの程度ご存じですか？","ENG":"How much do you know about spiders, Boss?","TWN":"老闆你對於蜘蛛的認知有多少？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"생김새 때문에 사람들이 싫어하지만, 생태계에 없어서는 안 될 익충이죠.","JPN":"見た目のせいで嫌われてはいますが、生態系になくてはならない益虫です。","ENG":"I know people despise them for how they look, but they are an essential and beneficial part of the ecosystem.","TWN":"蜘蛛因為長得不討喜而被討厭，但牠卻是在態系中不可或缺的益蟲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사회적 활동이라는 건 저에게 맞지 않는 옷 같은 거라서요.","JPN":"社会的活動というのは、私にとっては似合わない服のようなものですから。","ENG":"I find social activities uncomfortable, like clothes that don't fit me.","TWN":"社交活動對我來說就像是不合身的衣服。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"조금 거친 모습을 보여도 이해해 주신다면, 그만큼의 몫을 할 준비는 되어 있어요.","JPN":"少々乱暴なところを見せても理解してくださるのなら、相応の役目を果たす準備はできています。","ENG":"If you could be understanding of my rough methods, I'm ready to do my part.","TWN":"若你能包容我稍微粗魯的那一面，那我也會盡到我該盡的責任。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이제 만족하셨나요?","JPN":"これで満足されましたか？","ENG":"Are you satisfied now?","TWN":"這樣你滿意嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"충분히 사교적이었다니, 그런 낯부끄러운 평가는…….","JPN":"十分に社交的だったなど、そんな恥ずかしい評価は……","ENG":"What do you mean I was sociable enough? Such an embarrassing evaluation...","TWN":"什麼很懂得社交，這是什麼害羞的評語……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"감사히 받겠습니다. 훈련해 온 보람이 있었네요.","JPN":"ありがとうございます。訓練してきた甲斐がありました。","ENG":"Will be gratefully accepted. I guess all that training did pay off.","TWN":"那就心領囉。訓練這麼久是有意義的呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};